import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, Search, Edit } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminArtworks = () => {
  const [artworks, setArtworks] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchData = async () => {
    try {
      const res: any = await AdminService.getAllArtworks();
      
      /**
       * LOGIC: 
       * 1. res.data is the Axios body.
       * 2. res.data.data is the Artwork array from our Backend Controller wrapper.
       */
      const actualData = res.data?.data;
      
      // If the backend sent { success: true, data: [...] }
      if (actualData && Array.isArray(actualData)) {
        setArtworks(actualData);
      } 
      // Fallback if safeGet returned the error shape or raw array
      else if (Array.isArray(res.data)) {
        setArtworks(res.data);
      } else {
        setArtworks([]);
      }
    } catch (err) {
      console.error("Fetch Error:", err);
      setArtworks([]);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleDelete = async (id: string) => {
    if (!window.confirm("Permanent Archive Deletion?")) return;
    try {
      await AdminService.deleteArtwork(id);
      toast.success("Piece Removed");
      fetchData();
    } catch (err) {
      toast.error("Delete Failed");
    }
  };

  const filtered = artworks.filter(art => 
    art.Title_In_English?.toLowerCase().includes(search.toLowerCase()) || 
    art.Artwork_ID?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase italic text-white tracking-tighter">
            Gallery <span className="text-primary">Artworks</span>
          </h1>
          <p className="text-gray-500 font-bold uppercase text-[9px] tracking-[0.2em] mt-2">Visual Content Management</p>
        </div>
        <Link to="/admin/artworks/add" className="bg-primary text-black px-8 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-white transition-all shadow-lg shadow-primary/10">
          <Plus size={16} className="inline mr-1" /> Catalog Piece
        </Link>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
        <input 
          placeholder="Filter by ID or English Title..." 
          className="w-full bg-white/5 border border-white/10 p-4 pl-12 rounded-2xl outline-none focus:border-primary text-white text-xs font-bold transition-colors"
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filtered.length > 0 ? (
          filtered.map((art: any) => (
            <div key={art._id || art.Artwork_ID} className="bg-[#0f0f0f] rounded-[2.5rem] overflow-hidden border border-white/5 group hover:border-white/10 transition-all">
              <div className="h-56 bg-white/5 flex items-center justify-center overflow-hidden relative">
                <img 
                  src={art.Cloudinary_Image_URL || art.Film_Image_URL || 'https://via.placeholder.com/400x300?text=No+Image+Available'} 
                  className="w-full h-full object-cover transition-transform group-hover:scale-105 duration-700" 
                  alt={art.Title_In_English} 
                />
                <div className="absolute top-4 left-4 bg-black/60 backdrop-blur-md px-3 py-1 rounded-lg border border-white/10 text-[9px] font-black uppercase tracking-widest text-primary">
                  {art.Artwork_ID}
                </div>
              </div>
              <div className="p-8">
                <h4 className="font-black uppercase text-xs italic truncate text-white mb-1">{art.Title_In_English || 'Untitled Piece'}</h4>
                <p className="text-[10px] font-bold text-gray-500 mb-6 uppercase tracking-widest">Artist: {art.Artist_Name || art.Artist_ID}</p>
                <div className="flex gap-2">
                  <Link 
                    to={`/admin/artworks/edit/${art.Artwork_ID}`} 
                    className="flex-1 py-3 bg-white/5 rounded-xl font-black text-[9px] uppercase text-center text-white hover:bg-white hover:text-black transition-all"
                  >
                    Modify
                  </Link>
                  <button 
                    onClick={() => handleDelete(art.Artwork_ID)} 
                    className="px-4 py-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"
                  >
                    <Trash2 size={14}/>
                  </button>
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="col-span-full py-20 text-center border-2 border-dashed border-white/5 rounded-[3rem]">
            <p className="text-gray-600 font-black uppercase text-[10px] tracking-widest">No matching records found in gallery</p>
          </div>
        )}
      </div>
    </div>
  );
};
